exec('import csv,json,math,os,re,sqlite3\nfrom pathlib import Path\nfrom uuid import uuid4\nfrom fastapi import FastAPI,File,Form,HTTPException,UploadFile\nfrom fastapi.responses import FileResponse\nfrom fastapi.staticfiles import StaticFiles\nfrom pydantic import BaseModel\nfrom openpyxl import Workbook\nAPP_NAME="ワンさんツール"\nBASE=Path(os.getenv("APP_DATA_DIR","data"))\nUPLOAD_DIR=BASE/"uploads"\nOUTPUT_DIR=BASE/"outputs"\nDB=BASE/"app.sqlite3"\nfor d in (BASE,UPLOAD_DIR,OUTPUT_DIR):\n    d.mkdir(parents=True,exist_ok=True)\nALLOW={x.strip() for x in os.getenv("NOTE_ID_ALLOWLIST","demo-note-001,demo-note-002,member-test").split(",") if x.strip()}\nAUTH_MODE=os.getenv("NOTE_AUTH_MODE","allowlist")\nLIFF_ID=os.getenv("LIFF_ID","")\nTARGET_DRIVE_FOLDER_ID=os.getenv("TARGET_DRIVE_FOLDER_ID","11cA-CrY7rjlQlzdXywpT3i7PLRrXxOgD")\nRENTABLE_RATIO=float(os.getenv("RENTABLE_RATIO","0.82"))\napp=FastAPI(title=APP_NAME,version="1.1.0")\nstatic_dir=Path(__file__).parent/"static"\nif static_dir.exists():\n    app.mount("/static",StaticFiles(directory=static_dir),name="static")\nclass SessionRequest(BaseModel):\n    note_id:str\ndef _conn():\n    c=sqlite3.connect(DB)\n    c.row_factory=sqlite3.Row\n    return c\ndef init_db():\n    with _conn() as c:\n        c.executescript("CREATE TABLE IF NOT EXISTS sessions(token TEXT PRIMARY KEY,note_id TEXT NOT NULL);CREATE TABLE IF NOT EXISTS jobs(job_id TEXT PRIMARY KEY,token TEXT,note_id TEXT,result_json TEXT,output_dir TEXT);")\ninit_db()\ndef _allowed(note_id):\n    note_id=note_id.strip()\n    return bool(note_id) and (AUTH_MODE.lower()=="open" or note_id in ALLOW)\ndef _num(pattern,text):\n    m=re.search(pattern,text,re.I)\n    return float(m.group(1)) if m else None\nZONINGS=["第一種低層住居専用地域","第二種低層住居専用地域","第一種中高層住居専用地域","第二種中高層住居専用地域","第一種住居地域","第二種住居地域","準住居地域","田園住居地域","近隣商業地域","商業地域","準工業地域","工業地域","工業専用地域"]\ndef _zoning(text):\n    for z in ZONINGS:\n        if z in text:\n            return z\n    m=re.search("用途地域[:： ]*([^\\n]+)",text)\n    return m.group(1).strip() if m else None\ndef _address(text):\n    for line in text.splitlines():\n        if line.startswith(("所在地","住所","地番")):\n            return re.sub("^(所在地|住所|地番)[:： ]*","",line).strip()\n    return None\ndef _round(v,nd=2):\n    return round(v,nd) if v is not None else None\ndef _basis_step(title,formula,substitution,result,comment=""):\n    return {"title":title,"formula":formula,"substitution":substitution,"result":result,"comment":comment}\ndef analyze_text(text):\n    land=_num("([0-9]+(?:[.][0-9]+)?)(?:㎡|m2|m²|平米)",text)\n    tsubo=_num("([0-9]+(?:[.][0-9]+)?)坪",text)\n    land_source="㎡表記"\n    if land is None and tsubo is not None:\n        land=tsubo*3.305785; land_source=f"坪表記を㎡換算: {tsubo}坪 × 3.305785"\n    bcr=_num("(?:建ぺい率|建蔽率|BCR)[^0-9]{0,20}([0-9]{2,4}(?:[.][0-9]+)?)",text)\n    far=_num("(?:容積率|FAR)[^0-9]{0,20}([0-9]{2,4}(?:[.][0-9]+)?)",text)\n    road=_num("(?:前面道路|道路幅員|幅員)[^0-9]{0,20}([0-9]+(?:[.][0-9]+)?)",text)\n    avg=_num("(?:平均住戸面積|平均住戸|1戸|一戸)[^0-9]{0,20}([0-9]+(?:[.][0-9]+)?)(?:㎡|m2|m²|平米)",text) or 45.0\n    zone=_zoning(text)\n    coef=0.6 if zone and any(k in zone for k in ["商業","工業"]) else 0.4\n    coef_reason="商業系・工業系として0.6を使用" if coef==0.6 else "住居系または用途地域不明の安全側概算として0.4を使用"\n    road_far=road*coef*100 if road is not None else None\n    applied=far\n    applied_reason="指定容積率をそのまま使用"\n    if far is not None and road is not None and road<12:\n        applied=min(far,road_far); applied_reason="前面道路幅員が12m未満なので、指定容積率と道路幅員制限の小さい方を使用"\n    footprint=land*bcr/100 if land is not None and bcr is not None else None\n    total=land*applied/100 if land is not None and applied is not None else None\n    rentable=total*RENTABLE_RATIO if total is not None else None\n    floors=max(1,math.ceil(total/footprint)) if total and footprint else None\n    units=max(1,math.floor(rentable/avg)) if rentable else None\n    missing=[k for k,v in {"土地面積":land,"建ぺい率":bcr,"容積率":far,"前面道路幅員":road,"用途地域":zone}.items() if v is None]\n    steps=[]\n    steps.append(_basis_step("入力値の読取","OCR/補助テキストから土地面積・用途地域・建ぺい率・容積率・前面道路幅員を抽出",f"土地面積={_round(land)}㎡, 用途地域={zone}, 建ぺい率={bcr}%, 容積率={far}%, 前面道路幅員={road}m",land_source,"未読取の項目がある場合は不足項目として表示"))\n    if footprint is not None:\n        steps.append(_basis_step("最大建築面積","土地面積 × 建ぺい率 ÷ 100",f"{_round(land)}㎡ × {bcr}% ÷ 100",f"{_round(footprint)}㎡","1階あたりの建築面積の概算上限"))\n    if road_far is not None:\n        steps.append(_basis_step("道路幅員による容積率上限","前面道路幅員 × 係数 × 100",f"{road}m × {coef} × 100",f"{_round(road_far)}%",coef_reason))\n    if applied is not None:\n        sub=f"min({far}%, {_round(road_far)}%)" if road_far is not None and road is not None and road<12 else f"{far}%"\n        steps.append(_basis_step("適用容積率","指定容積率と道路幅員制限を比較",sub,f"{_round(applied)}%",applied_reason))\n    if total is not None:\n        steps.append(_basis_step("最大延床面積","土地面積 × 適用容積率 ÷ 100",f"{_round(land)}㎡ × {_round(applied)}% ÷ 100",f"{_round(total)}㎡","容積対象床面積の概算"))\n    if rentable is not None:\n        steps.append(_basis_step("想定賃貸面積","最大延床面積 × 賃貸有効率",f"{_round(total)}㎡ × {RENTABLE_RATIO}",f"{_round(rentable)}㎡","廊下・階段・共用部等を除くための内部仮定。環境変数RENTABLE_RATIOで変更可能"))\n    if units is not None:\n        steps.append(_basis_step("想定戸数","想定賃貸面積 ÷ 平均住戸面積 を切り捨て",f"{_round(rentable)}㎡ ÷ {avg}㎡",f"{units}戸","平均住戸面積が未入力なら45㎡を使用"))\n    if floors is not None:\n        steps.append(_basis_step("想定階数","最大延床面積 ÷ 最大建築面積 を切り上げ",f"{_round(total)}㎡ ÷ {_round(footprint)}㎡",f"{floors}階","必要な延床面積を建築面積上限で割った概算"))\n    cautions=["この結果は初期検討用の概算であり、建築可否・収益性・法適合を保証しません。","斜線制限、日影規制、高度地区、防火地域、条例、接道、敷地形状、天空率、駐車場附置義務は別途確認してください。"]\n    if road_far is not None and far is not None and applied!=far:\n        cautions.append("前面道路幅員による容積率制限を反映しています。")\n    if missing:\n        cautions.append("不足項目: "+", ".join(missing))\n    return {"tool_name":APP_NAME,"address":_address(text),"zoning":zone,"inputs":{"land_area_m2":_round(land),"building_coverage_ratio_percent":bcr,"floor_area_ratio_percent":far,"road_width_m":road,"avg_unit_size_m2":avg,"rentable_ratio":RENTABLE_RATIO},"calculation":{"road_coefficient":coef,"road_limited_far_percent":_round(road_far),"applied_far_percent":_round(applied),"max_footprint_m2":_round(footprint),"max_total_floor_area_m2":_round(total),"estimated_rentable_area_m2":_round(rentable),"estimated_floors":floors,"estimated_units":units},"calculation_basis":{"summary":"入力値、式、代入値、結果、注意点をステップごとに表示します。","steps":steps,"assumptions":["住居系または用途地域不明は道路幅員係数0.4で概算","商業系・工業系は道路幅員係数0.6で概算","賃貸有効率は初期値0.82。RENTABLE_RATIOで変更可能","平均住戸面積が未入力の場合は45㎡を使用","端数処理: 戸数は切り捨て、階数は切り上げ"]},"confidence":_round(max(0.2,1.0-0.13*len(missing))),"cautions":cautions}\ndef _flatten(prefix,value,rows):\n    if isinstance(value,dict):\n        for k,v in value.items():\n            _flatten((prefix+"."+k) if prefix else k,v,rows)\n    elif isinstance(value,list):\n        for i,item in enumerate(value,1):\n            _flatten(f"{prefix}.{i}",item,rows)\n    else:\n        rows.append((prefix,value))\ndef write_exports(job_id,result,extracted_text,out_dir):\n    out_dir.mkdir(parents=True,exist_ok=True)\n    rows=[]\n    _flatten("",result,rows)\n    csv_path=out_dir/(job_id+".csv")\n    with csv_path.open("w",newline="",encoding="utf-8-sig") as fp:\n        w=csv.writer(fp); w.writerow(["key","value"]); w.writerows(rows)\n    txt_path=out_dir/(job_id+".txt")\n    with txt_path.open("w",encoding="utf-8") as fp:\n        fp.write(APP_NAME+" 計算結果"+chr(10)+"="*28+chr(10))\n        for step in result.get("calculation_basis",{}).get("steps",[]):\n            fp.write(chr(10)+step["title"]+chr(10)); fp.write("式: "+step["formula"]+chr(10)); fp.write("代入: "+step["substitution"]+chr(10)); fp.write("結果: "+str(step["result"])+chr(10)); fp.write("補足: "+step.get("comment","")+chr(10))\n        fp.write(chr(10)+"--- full result ---"+chr(10)+json.dumps(result,ensure_ascii=False,indent=2)+chr(10)+"--- extracted text ---"+chr(10)+extracted_text)\n    xlsx_path=out_dir/(job_id+".xlsx")\n    wb=Workbook(); ws=wb.active; ws.title="計算結果"; ws.append(["key","value"])\n    for row in rows:\n        ws.append(list(row))\n    basis=wb.create_sheet("計算根拠"); basis.append(["項目","式","代入値","結果","補足"])\n    for step in result.get("calculation_basis",{}).get("steps",[]):\n        basis.append([step["title"],step["formula"],step["substitution"],step["result"],step.get("comment","")])\n    tx=wb.create_sheet("OCR入力"); tx.append(["text"]); tx.append([extracted_text]); wb.save(xlsx_path)\n    return {"csv":csv_path,"txt":txt_path,"xlsx":xlsx_path}\n@app.get("/")\ndef index():\n    p=static_dir/"index.html"\n    return FileResponse(p) if p.exists() else {"app":APP_NAME}\n@app.get("/api/health")\ndef health():\n    return {"status":"ok","app":APP_NAME}\n@app.get("/api/config")\ndef config():\n    return {"app_name":APP_NAME,"liff_id":LIFF_ID,"note_auth_mode":AUTH_MODE,"demo_note_ids":sorted(ALLOW) if AUTH_MODE=="allowlist" else [],"target_drive_folder_id":TARGET_DRIVE_FOLDER_ID}\n@app.post("/api/session")\ndef create_session(payload:SessionRequest):\n    note_id=payload.note_id.strip()\n    if not _allowed(note_id):\n        raise HTTPException(status_code=403,detail="note ID is not allowed")\n    token=uuid4().hex\n    with _conn() as c:\n        c.execute("INSERT INTO sessions(token,note_id) VALUES(?,?)",(token,note_id))\n    return {"token":token,"note_id":note_id}\n@app.post("/api/analyze")\nasync def analyze(token:str=Form(...),file:UploadFile=File(...),manual_text:str=Form("")):\n    with _conn() as c:\n        s=c.execute("SELECT * FROM sessions WHERE token=?",(token,)).fetchone()\n    if s is None:\n        raise HTTPException(status_code=401,detail="invalid session token")\n    job_id=uuid4().hex; safe_name=Path(file.filename or "upload.bin").name; content=await file.read(); upload_path=UPLOAD_DIR/(job_id+"_"+safe_name); upload_path.write_bytes(content)\n    extracted=manual_text.strip()+chr(10)+f"upload_name: {safe_name}"+chr(10)+f"file_size_bytes: {len(content)}"\n    result=analyze_text(extracted); out_dir=OUTPUT_DIR/job_id; write_exports(job_id,result,extracted,out_dir)\n    with _conn() as c:\n        c.execute("INSERT INTO jobs(job_id,token,note_id,result_json,output_dir) VALUES(?,?,?,?,?)",(job_id,token,s["note_id"],json.dumps(result,ensure_ascii=False),str(out_dir)))\n    return {"job_id":job_id,"result":result,"exports":{"csv":f"/api/jobs/{job_id}/exports/csv","xlsx":f"/api/jobs/{job_id}/exports/xlsx","txt":f"/api/jobs/{job_id}/exports/txt"}}\n@app.get("/api/jobs/{job_id}")\ndef get_job(job_id):\n    with _conn() as c:\n        row=c.execute("SELECT * FROM jobs WHERE job_id=?",(job_id,)).fetchone()\n    if row is None:\n        raise HTTPException(status_code=404,detail="job not found")\n    d=dict(row); d["result"]=json.loads(d.pop("result_json")); return d\n@app.get("/api/jobs/{job_id}/exports/{kind}")\ndef download(job_id,kind):\n    if kind not in {"csv","xlsx","txt"}:\n        raise HTTPException(status_code=404,detail="unsupported export type")\n    with _conn() as c:\n        row=c.execute("SELECT output_dir FROM jobs WHERE job_id=?",(job_id,)).fetchone()\n    if row is None:\n        raise HTTPException(status_code=404,detail="job not found")\n    path=Path(row["output_dir"])/(job_id+"."+kind)\n    if not path.exists():\n        raise HTTPException(status_code=404,detail="export not found")\n    media={"csv":"text/csv","xlsx":"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet","txt":"text/plain"}\n    return FileResponse(path,media_type=media[kind],filename=path.name)\n')